// The brand mark: a jar (with cookies inside) on a dark tile — matches the
// PWA icon generated by scripts/gen-icons.mjs. "Cookie Jar" is the name; the
// logo is the jar.
function Cookie({ cx, cy, r }: { cx: number; cy: number; r: number }) {
  const chips: [number, number][] = [
    [-0.32, -0.28], [0.3, -0.18], [0.28, 0.3], [-0.22, 0.3], [0.02, 0.02],
  ]
  return (
    <>
      <circle cx={cx} cy={cy} r={r} fill="#f0d29a" />
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#d9b878" strokeWidth={r * 0.06} />
      {chips.map(([dx, dy], i) => (
        <circle key={i} cx={cx + dx * r} cy={cy + dy * r} r={r * 0.13} fill="#7a4a1e" />
      ))}
    </>
  )
}

export default function CookieJarLogo({ size = 40 }: { size?: number }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 512 512"
      className="shrink-0"
      style={{ boxShadow: '0 0 0 1px rgba(255,255,255,0.06) inset' }}
    >
      <defs>
        <radialGradient id="cjl-bg" cx="50%" cy="38%" r="75%">
          <stop offset="0" stopColor="#242427" />
          <stop offset="1" stopColor="#161618" />
        </radialGradient>
        <radialGradient id="cjl-glow" cx="50%" cy="50%" r="50%">
          <stop offset="0" stopColor="rgba(229,72,77,0.34)" />
          <stop offset="1" stopColor="rgba(229,72,77,0)" />
        </radialGradient>
        <clipPath id="cjl-clip">
          <rect x="162" y="182" width="188" height="220" rx="36" />
        </clipPath>
      </defs>

      <rect x="0" y="0" width="512" height="512" rx="112" fill="url(#cjl-bg)" />
      <circle cx="256" cy="300" r="190" fill="url(#cjl-glow)" />

      {/* lid */}
      <rect x="170" y="120" width="172" height="40" rx="14" fill="#e5484d" />
      <rect x="160" y="152" width="192" height="22" rx="9" fill="#aa2429" />

      {/* glass body */}
      <rect
        x="156"
        y="176"
        width="200"
        height="232"
        rx="40"
        fill="rgba(229,72,77,0.10)"
        stroke="#e5484d"
        strokeWidth="11"
      />

      {/* cookies inside */}
      <g clipPath="url(#cjl-clip)">
        <Cookie cx={214} cy={348} r={46} />
        <Cookie cx={308} cy={356} r={42} />
        <Cookie cx={262} cy={296} r={44} />
      </g>

      {/* glass highlight */}
      <rect x="180" y="200" width="20" height="150" rx="10" fill="rgba(255,255,255,0.10)" />
    </svg>
  )
}
